/**
 * Bizarro companion-mask path. Mirrors aether's
 * `gcp-coordinator.ts` :: `enableBizarroPrefill` plumbing
 * (dispatchBizarroCompanion / countIdleDownstreamSlots / bizarroMasks).
 *
 * Invariants under test:
 *   - Default (`enableBizarro: false`) is a no-op: no `bizarroForward`
 *     calls, no counters on the result.
 *   - When enabled, dispatches fire only when downstream slots are idle.
 *   - A failing `bizarroForward` is silently swallowed: nominal completes.
 *   - Retirement counter increments when nominal argmax falls outside the
 *     speculatively-computed reject mask.
 */

import { describe, expect, it } from 'vitest';

import { Pipeline } from '../src/pipeline';
import { Station } from '../src/station';

const HIDDEN_DIM = 4;
const VOCAB = 8;

interface BizarroCallRecord {
  targetChunkIdx: number;
  startPos: number;
  sequenceLength: number;
  targetPosition: number;
  inFlightSnapshot: ReadonlyArray<number>; // node indices currently busy
}

/**
 * Build a per-station fetcher that supports the production wire-shape AND
 * an `X-Forward-Mode: bizarro` header. The bizarro branch returns an
 * `X-Reject-Mask` JSON header and a small body so `Station.bizarroForward`
 * has something to parse.
 *
 * The fetcher records bizarro vs nominal calls separately so the test can
 * assert dispatch counts and idle-slot timing.
 */
function buildMockStation(opts: {
  startLayer: number;
  endLayer: number;
  role?: 'entry' | 'mid' | 'exit';
  /** If set, bizarroForward returns this rejectMask. */
  rejectMask?: number[] | null;
  /** If set, bizarroForward fails (HTTP 500). */
  bizarroFails?: boolean;
  /** Latency in ms applied to nominal forward calls. */
  forwardLatencyMs?: number;
  /** Latency in ms applied to bizarro forward calls. */
  bizarroLatencyMs?: number;
  hiddenDim?: number;
  vocabSize?: number;
}) {
  const hiddenDim = opts.hiddenDim ?? HIDDEN_DIM;
  const vocabSize = opts.vocabSize ?? VOCAB;
  const nominalForwards: { startPos: number; sequenceLength: number }[] = [];
  const bizarroForwards: { startPos: number; sequenceLength: number; targetPosition: number }[] = [];

  const fetcher = {
    fetch: async (req: Request): Promise<Response> => {
      const url = new URL(req.url);
      const path = url.pathname;
      const startPos = parseInt(req.headers.get('X-Position') ?? '0', 10);
      const sequenceLength = parseInt(req.headers.get('X-Sequence-Length') ?? '1', 10);
      const tokenCount = parseInt(req.headers.get('X-Token-Count') ?? '0', 10);
      const mode = req.headers.get('X-Forward-Mode');
      const targetPositionHeader = req.headers.get('X-Target-Position');
      // Drain body so the connection is reusable.
      await req.arrayBuffer();

      if (path === '/embed') {
        const out = new Float32Array(tokenCount * hiddenDim);
        for (let i = 0; i < out.length; i++) out[i] = i + 1;
        return makeBinaryResponse(out);
      }

      if (path === '/forward' && mode === 'bizarro') {
        if (opts.bizarroLatencyMs && opts.bizarroLatencyMs > 0) {
          await new Promise((r) => setTimeout(r, opts.bizarroLatencyMs));
        }
        bizarroForwards.push({
          startPos,
          sequenceLength,
          targetPosition: targetPositionHeader ? parseInt(targetPositionHeader, 10) : -1,
        });
        if (opts.bizarroFails) {
          return new Response('bizarro boom', { status: 500 });
        }
        const headers: Record<string, string> = {
          'Content-Type': 'application/octet-stream',
        };
        if (opts.rejectMask !== null && opts.rejectMask !== undefined) {
          headers['X-Reject-Mask'] = JSON.stringify(opts.rejectMask);
        }
        // Body content doesn't matter for bizarro — Station drains it.
        const body = new ArrayBuffer(hiddenDim * 4);
        return new Response(body, { headers });
      }

      if (path === '/forward') {
        if (opts.forwardLatencyMs && opts.forwardLatencyMs > 0) {
          await new Promise((r) => setTimeout(r, opts.forwardLatencyMs));
        }
        nominalForwards.push({ startPos, sequenceLength });
        const out = new Float32Array(sequenceLength * hiddenDim);
        // Make argmax deterministic: largest value at index 3 of last token.
        for (let i = 0; i < out.length; i++) out[i] = (i + 1) * 0.01;
        const lastTokenOff = (sequenceLength - 1) * hiddenDim;
        out[lastTokenOff + 3] = 99;
        return makeBinaryResponse(out);
      }

      if (path === '/lm-head') {
        const reply = new Float32Array(vocabSize);
        reply[3] = 1.0;
        return makeBinaryResponse(reply);
      }

      return new Response('not found', { status: 404 });
    },
  };

  const station = new Station({
    endpoint: fetcher,
    startLayer: opts.startLayer,
    endLayer: opts.endLayer,
    role: opts.role,
    baseUrl: `http://station-${opts.startLayer}`,
  });

  return { station, nominalForwards, bizarroForwards };
}

function makeBinaryResponse(arr: Float32Array): Response {
  const buf = new ArrayBuffer(arr.byteLength);
  new Uint8Array(buf).set(new Uint8Array(arr.buffer, arr.byteOffset, arr.byteLength));
  return new Response(buf, { headers: { 'Content-Type': 'application/octet-stream' } });
}

/**
 * Spy Station that intercepts `bizarroForward` so we can assert dispatch
 * timing without a real fetcher. Wraps a real Station for `forward`/`embed`/
 * `lmHead`.
 */
class SpyStation extends Station {
  readonly bizarroCalls: BizarroCallRecord[] = [];
  readonly bizarroResolve: (call: BizarroCallRecord) => Promise<{ rejectMask: number[] } | null>;

  constructor(
    inner: Station,
    resolver: (call: BizarroCallRecord) => Promise<{ rejectMask: number[] } | null>,
  ) {
    super({
      endpoint: { fetch: () => Promise.reject(new Error('SpyStation does not fetch')) },
      startLayer: inner.startLayer,
      endLayer: inner.endLayer,
      role: inner.role,
    });
    // Replace prototype methods with proxies to inner.
    this.forward = inner.forward.bind(inner);
    this.embed = inner.embed.bind(inner);
    this.lmHead = inner.lmHead.bind(inner);
    this.bizarroResolve = resolver;
  }

  override async bizarroForward(args: {
    residual: Float32Array;
    startPos: number;
    sequenceLength: number;
    targetPosition: number;
    requestId?: string;
  }): Promise<{ rejectMask: number[] } | null> {
    const rec: BizarroCallRecord = {
      targetChunkIdx: -1, // filled by caller-side via inspection
      startPos: args.startPos,
      sequenceLength: args.sequenceLength,
      targetPosition: args.targetPosition,
      inFlightSnapshot: [], // unused unless test wants to inspect
    };
    this.bizarroCalls.push(rec);
    return this.bizarroResolve(rec);
  }
}

describe('Pipeline.pipelinedPrefill — bizarro disabled (default)', () => {
  it('does not dispatch bizarro companions when enableBizarro is unset', async () => {
    const s0 = buildMockStation({ startLayer: 0, endLayer: 8, role: 'entry' });
    const s1 = buildMockStation({ startLayer: 8, endLayer: 16 });
    const s2 = buildMockStation({ startLayer: 16, endLayer: 24, role: 'exit' });
    const pipeline = new Pipeline({
      stations: [s0.station, s1.station, s2.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB,
    });
    const result = await pipeline.pipelinedPrefill({
      promptTokens: new Uint32Array(12).map((_, i) => i + 1),
    });
    expect(s0.bizarroForwards.length).toBe(0);
    expect(result.bizarroDispatches).toBeUndefined();
    expect(result.bizarroRetirements).toBeUndefined();
  });

  it('does not dispatch bizarro companions when enableBizarro is explicitly false', async () => {
    const s0 = buildMockStation({ startLayer: 0, endLayer: 8, role: 'entry' });
    const s1 = buildMockStation({ startLayer: 8, endLayer: 16, role: 'exit' });
    const pipeline = new Pipeline({
      stations: [s0.station, s1.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB,
      enableBizarro: false,
    });
    await pipeline.pipelinedPrefill({
      promptTokens: new Uint32Array(8).map((_, i) => i + 1),
    });
    expect(s0.bizarroForwards.length).toBe(0);
  });
});

describe('Pipeline.pipelinedPrefill — bizarro enabled', () => {
  it('fires speculative dispatches and reports counters in the result', async () => {
    // 3 stations, 12 tokens, chunkSize=4 -> 3 chunks. Bizarro dispatches
    // happen each time station 0 is re-armed AND a downstream slot is idle.
    const s0 = buildMockStation({
      startLayer: 0,
      endLayer: 8,
      role: 'entry',
      rejectMask: [0, 1, 2, 4, 5, 6, 7], // excludes 3 -> argmax 3 will retire
    });
    const s1 = buildMockStation({ startLayer: 8, endLayer: 16 });
    const s2 = buildMockStation({ startLayer: 16, endLayer: 24, role: 'exit' });
    const pipeline = new Pipeline({
      stations: [s0.station, s1.station, s2.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB,
      enableBizarro: true,
    });

    const result = await pipeline.pipelinedPrefill({
      promptTokens: new Uint32Array(12).map((_, i) => i + 1),
    });

    expect(result.bizarroDispatches).toBeDefined();
    expect(result.bizarroRetirements).toBeDefined();
    expect(result.bizarroDispatches!).toBeGreaterThan(0);
    // Each bizarro dispatch should target station 0 only (mirrors aether's
    // `nodeEntries[0][1]` reference).
    expect(s0.bizarroForwards.length).toBe(result.bizarroDispatches!);
    expect(s1.bizarroForwards.length).toBe(0);
    expect(s2.bizarroForwards.length).toBe(0);
  });

  it('only dispatches when downstream slots are idle (countIdleDownstreamSlots > 0)', async () => {
    // Use a SpyStation that records the inFlight state at dispatch time
    // (best-effort via call ordering). With 3 stations, every bizarro
    // dispatch happens immediately after we re-arm station 0; if the
    // implementation honored the idle-slot guard and the test harness has
    // multiple downstream stations free, we should see at least one fire.
    const s0Inner = buildMockStation({ startLayer: 0, endLayer: 8, role: 'entry' });
    const s1Inner = buildMockStation({ startLayer: 8, endLayer: 16 });
    const s2Inner = buildMockStation({ startLayer: 16, endLayer: 24, role: 'exit' });
    const spy = new SpyStation(s0Inner.station, async () => ({
      rejectMask: [0, 1, 2, 4, 5, 6, 7], // exclude 3
    }));

    const pipeline = new Pipeline({
      stations: [spy, s1Inner.station, s2Inner.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB,
      enableBizarro: true,
    });

    const result = await pipeline.pipelinedPrefill({
      promptTokens: new Uint32Array(12).map((_, i) => i + 1),
    });
    // 3 chunks, station 0 re-armed twice (after seed). Both re-arms see
    // downstream slots idle the moment they complete (no latency in this
    // test), so we expect at least one dispatch.
    expect(spy.bizarroCalls.length).toBeGreaterThan(0);
    expect(result.bizarroDispatches).toBe(spy.bizarroCalls.length);
    // targetPosition matches startPos + sequenceLength - 1
    for (const c of spy.bizarroCalls) {
      expect(c.targetPosition).toBe(c.startPos + c.sequenceLength - 1);
    }
  });

  it('skips bizarro dispatch when there are no downstream slots (single-station)', async () => {
    // N=1: countIdleDownstreamSlots iterates `i in 1..0` → 0 → never fires.
    const only = buildMockStation({ startLayer: 0, endLayer: 32 });
    const pipeline = new Pipeline({
      stations: [only.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB,
      enableBizarro: true,
    });
    const result = await pipeline.pipelinedPrefill({
      promptTokens: new Uint32Array(40).map((_, i) => i + 1),
    });
    expect(only.bizarroForwards.length).toBe(0);
    expect(result.bizarroDispatches).toBe(0);
    expect(result.bizarroRetirements).toBe(0);
  });

  it('swallows bizarroForward failures without crashing the pipeline', async () => {
    const s0 = buildMockStation({
      startLayer: 0,
      endLayer: 8,
      role: 'entry',
      bizarroFails: true,
    });
    const s1 = buildMockStation({ startLayer: 8, endLayer: 16 });
    const s2 = buildMockStation({ startLayer: 16, endLayer: 24, role: 'exit' });
    const pipeline = new Pipeline({
      stations: [s0.station, s1.station, s2.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB,
      enableBizarro: true,
    });

    const result = await pipeline.pipelinedPrefill({
      promptTokens: new Uint32Array(12).map((_, i) => i + 1),
    });

    // Pipeline still completes without poisoning.
    expect(result.poisoned).toBe(false);
    expect(result.poisonChunk).toBe(-1);
    // Bizarro dispatches were still attempted.
    expect(result.bizarroDispatches!).toBeGreaterThan(0);
    // None succeeded — failed bizarroForward returns null, no mask stashed.
    expect(result.bizarroRetirements).toBe(0);
  });

  it('also swallows synchronous throws from bizarroForward', async () => {
    const s0Inner = buildMockStation({ startLayer: 0, endLayer: 8, role: 'entry' });
    const s1Inner = buildMockStation({ startLayer: 8, endLayer: 16 });
    const s2Inner = buildMockStation({ startLayer: 16, endLayer: 24, role: 'exit' });
    const spy = new SpyStation(s0Inner.station, () => {
      // Synchronous throw inside the .then chain.
      return Promise.reject(new Error('bizarro went sideways'));
    });

    const pipeline = new Pipeline({
      stations: [spy, s1Inner.station, s2Inner.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB,
      enableBizarro: true,
    });

    const result = await pipeline.pipelinedPrefill({
      promptTokens: new Uint32Array(12).map((_, i) => i + 1),
    });

    expect(result.poisoned).toBe(false);
    expect(spy.bizarroCalls.length).toBeGreaterThan(0);
    expect(result.bizarroRetirements).toBe(0);
  });

  it('counts retirements when nominal argmax falls outside the reject mask', async () => {
    // Mock returns hidden states where argmax of last token = index 3.
    // rejectMask excludes 3 → "argmax ∉ mask" → retire.
    const s0Inner = buildMockStation({ startLayer: 0, endLayer: 8, role: 'entry' });
    const s1Inner = buildMockStation({ startLayer: 8, endLayer: 16 });
    const s2Inner = buildMockStation({ startLayer: 16, endLayer: 24, role: 'exit' });

    // Make bizarro slow enough to deliver ON the first chunk's retirement.
    // We resolve immediately — the .then mask-stash runs synchronously after
    // the next microtask so the mask is in `bizarroMasks` before the next
    // chunk completes through station 2.
    const spy = new SpyStation(s0Inner.station, async () => ({
      rejectMask: [0, 1, 2, 4, 5, 6, 7], // exclude 3
    }));

    const pipeline = new Pipeline({
      stations: [spy, s1Inner.station, s2Inner.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB,
      enableBizarro: true,
    });

    const result = await pipeline.pipelinedPrefill({
      promptTokens: new Uint32Array(12).map((_, i) => i + 1),
    });

    // At least one retirement: a bizarro mask was stashed and the chunk it
    // was speculated for retired with argmax = 3 ∉ mask.
    expect(result.bizarroDispatches!).toBeGreaterThan(0);
    expect(result.bizarroRetirements!).toBeGreaterThanOrEqual(1);
    // Retirements never exceed dispatches (each dispatch can produce at most
    // one stashed mask).
    expect(result.bizarroRetirements!).toBeLessThanOrEqual(result.bizarroDispatches!);
  });

  it('does not count retirements when nominal argmax is inside the reject mask', async () => {
    // rejectMask INCLUDES 3 → argmax IS rejected → no retirement.
    const s0Inner = buildMockStation({ startLayer: 0, endLayer: 8, role: 'entry' });
    const s1Inner = buildMockStation({ startLayer: 8, endLayer: 16 });
    const s2Inner = buildMockStation({ startLayer: 16, endLayer: 24, role: 'exit' });
    const spy = new SpyStation(s0Inner.station, async () => ({
      rejectMask: [3], // include 3
    }));

    const pipeline = new Pipeline({
      stations: [spy, s1Inner.station, s2Inner.station],
      hiddenDim: HIDDEN_DIM,
      vocabSize: VOCAB,
      enableBizarro: true,
    });

    const result = await pipeline.pipelinedPrefill({
      promptTokens: new Uint32Array(12).map((_, i) => i + 1),
    });
    expect(result.bizarroDispatches!).toBeGreaterThan(0);
    expect(result.bizarroRetirements).toBe(0);
  });
});
